arguments.argument:
startX=x startY=y endX=x endY=y var xChk,yChk; xChk=1; yChk=1 if xSpd<0 xChk=-1 if ySpd<0 yChk=-1
if xSpd!=0 endX=x+(64*xChk) if ySpd!=0 endY=y+(64*yChk)
if variable_local_exists("spriteChange") newSprite=spriteChange if variable_local_exists("newRangeX") drawRangeX=newRangeX if variable_local_exists("newRangeY") drawRangeY=newRangeY
